#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int M, x1, y1;
        scanf("%d %d %d", &M, &x1, &y1);
        long long sum = 0;
        for (int i = 0; i < M; i++) {
            int minX = (x1 < y1) ? x1 : y1;
            int maxX = (x1 > y1) ? x1 : y1;
            int maxVal = A[minX];
            for (int j = minX + 1; j <= maxX; j++) {
                if (A[j] > maxVal) {
                    maxVal = A[j];
                }
            }
            sum += maxVal;
            x1 = (x1 + 7) % (N - 1);
            y1 = (y1 + 11) % N;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

