import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int M = sc.nextInt();
            int x1 = sc.nextInt();
            int y1 = sc.nextInt();
            long sum = 0;
            for (int i = 0; i < M; i++) {
                int minX = Math.min(x1, y1);
                int maxX = Math.max(x1, y1);
                int maxVal = A[minX];
                for (int j = minX + 1; j <= maxX; j++) {
                    if (A[j] > maxVal) {
                        maxVal = A[j];
                    }
                }
                sum += maxVal;
                x1 = (x1 + 7) % (N - 1);
                y1 = (y1 + 11) % N;
            }
            System.out.println(sum);
        }
    }
}

